void initDeepLink() async {
  if (!await UniLinks.hasListener()) {
    throw Exception("Can't listen to deep links");
  }

  try {
    uriLinkStream.listen((Uri? uri) async {
      print('Received link: $uri');
      if (uri != null) {
        if (uri.host == 'profile' && uri.pathSegments.length > 1) {
          int userId = int.parse(uri.pathSegments[1]);
          Navigator.pushNamed(
            MyApp.navigatorKey.currentContext!,
            '/profile',
            arguments: userId,
          );
        } else if (uri.host == 'payment' && uri.path == 'confirm') {
          Navigator.pushNamed(
            MyApp.navigatorKey.currentContext!,
            '/payment/confirm',
          );
        }
      }
    });
  } catch (e) {
    print('Error listening to deep links: $e');
  }
}